questionvariables.text:
/* Baseline segments along AD: AB, BC, CD */
d1: 5 + rand(3); /* AB */
d2: 6 + rand(4); /* BC */
d3: 4 + rand(3); /* CD */

/* Offsets to the Left (L) and Right (R) */
hL: 4 + rand(3); /* Offset at B to vertex E (Left) */
hR: 5 + rand(3); /* Offset at C to vertex F (Right) */

/* Area Calculations */
/* Left Side: Triangle ABE + Triangle EBD */
/* Area ABE = 1/2 * base(AB) * height(hL) */
area_left1: 1/2 * d1 * hL;
/* Area EBD = 1/2 * base(BD) * height(hL). Note: BD = d2 + d3 */
area_left2: 1/2 * (d2 + d3) * hL;

/* Right Side: Triangle ACF + Triangle FCD */
/* Area ACF = 1/2 * base(AC) * height(hR). Note: AC = d1 + d2 */
area_right1: 1/2 * (d1 + d2) * hR;
/* Area FCD = 1/2 * base(CD) * height(hR) */
area_right2: 1/2 * d3 * hR;

/* Total Area */
ta: area_left1 + area_left2 + area_right1 + area_right2;
